{ title: "Ρωτώντας οδηγίες στη Βαρανάσι", scene: "Περπατάς στα στενά της Βαρανάσι και ψάχνεις έναν ναό κοντά στον ποταμό. Σταματάς έναν ντόπιο και ρωτάς ευγενικά.", lines: [{ who: "you", hi: "माफ़ कीजिए, मंदिर कहाँ है?", el: "Με συγχωρείτε, πού είναι ο ναός;" }, { who: "them", hi: "कौन सा मंदिर?", el: "Ποιος ναός;" }, { who: "you", hi: "गंगा के पास वाला मंदिर।", el: "Ο ναός κοντά στον Γάγγη." }, { who: "them", hi: "यहाँ से सीधा जाइए।", el: "Από εδώ πηγαίνετε ευθεία." }, { who: "you", hi: "फिर दाएँ या बाएँ?", el: "Μετά δεξιά ή αριστερά;" }, { who: "them", hi: "कोने पर बाएँ मुड़िए।", el: "Στη γωνία στρίψτε αριστερά." }, { who: "you", hi: "मंदिर पास है?", el: "Είναι κοντά ο ναός;" }, { who: "them", hi: "जी हाँ, पाँच मिनट।", el: "Ναι, πέντε λεπτά." }, { who: "you", hi: "यह रास्ता ठीक है?", el: "Είναι σωστός αυτός ο δρόμος;" }, { who: "them", hi: "हाँ, बिल्कुल ठीक है।", el: "Ναι, απολύτως σωστός." }, { who: "you", hi: "बहुत धन्यवाद।", el: "Ευχαριστώ πολύ." }, { who: "them", hi: "कोई बात नहीं।", el: "Δεν πειράζει." }] },
{ title: "Γεύμα σε εστιατόριο στο Μουμπάι", scene: "Κάθεσαι σε εστιατόριο στο Μουμπάι και θέλεις χορτοφαγικό φαγητό που να μην είναι πολύ πικάντικο. Ζητάς επίσης νερό και τον λογαριασμό.", lines: [{ who: "them", hi: "नमस्ते, मेन्यू चाहिए?", el: "Γεια σας, θέλετε μενού;" }, { who: "you", hi: "जी हाँ, मेन्यू दीजिए।", el: "Ναι, δώστε μου το μενού." }, { who: "them", hi: "आप क्या खाएँगे?", el: "Τι θα φάτε;" }, { who: "you", hi: "मैं शाकाहारी हूँ।", el: "Είμαι χορτοφάγος." }, { who: "them", hi: "शाकाहारी थाली अच्छी है।", el: "Η χορτοφαγική thali είναι καλή." }, { who: "you", hi: "कम मसालेदार चाहिए।", el: "Τη θέλω λιγότερο πικάντικη." }, { who: "them", hi: "ठीक है, कम मिर्च।", el: "Εντάξει, λίγο τσίλι." }, { who: "you", hi: "पानी भी दीजिए।", el: "Δώστε και νερό." }, { who: "them", hi: "ज़रूर, अभी लाता हूँ।", el: "Βεβαίως, το φέρνω τώρα." }, { who: "you", hi: "खाना बहुत अच्छा है।", el: "Το φαγητό είναι πολύ καλό." }, { who: "them", hi: "धन्यवाद।", el: "Ευχαριστώ." }, { who: "you", hi: "बिल दीजिए, कृपया।", el: "Δώστε μου τον λογαριασμό, παρακαλώ." }] },
{ title: "Αγορά εισιτηρίων τρένου", scene: "Βρίσκεσαι σε σταθμό στο Δελχί και θέλεις δύο εισιτήρια για Άγκρα. Ρωτάς για ώρα, αποβάθρα και καθυστέρηση.", lines: [{ who: "them", hi: "नमस्ते, कहाँ जाना है?", el: "Γεια σας, πού θέλετε να πάτε;" }, { who: "you", hi: "आगरा जाना है।", el: "Θέλω να πάω στην Άγκρα." }, { who: "them", hi: "कितने टिकट चाहिए?", el: "Πόσα εισιτήρια θέλετε;" }, { who: "you", hi: "दो टिकट चाहिए।", el: "Θέλω δύο εισιτήρια." }, { who: "them", hi: "सुबह दस बजे ट्रेन है।", el: "Υπάρχει τρένο στις δέκα το πρωί." }, { who: "you", hi: "प्लेटफ़ॉर्म नंबर क्या है?", el: "Ποιος είναι ο αριθμός αποβάθρας;" }, { who: "them", hi: "प्लेटफ़ॉर्म नंबर पाँच।", el: "Αποβάθρα αριθμός πέντε." }, { who: "you", hi: "ट्रेन देर से है?", el: "Το τρένο έχει καθυστέρηση;" }, { who: "them", hi: "जी नहीं, समय पर है।", el: "Όχι, είναι στην ώρα του." }, { who: "you", hi: "कुल कितना है?", el: "Πόσο είναι το σύνολο;" }, { who: "them", hi: "चार सौ रुपये।", el: "Τετρακόσιες ρουπίες." }, { who: "you", hi: "यह पैसे लीजिए।", el: "Πάρτε τα χρήματα." }] },
{ title: "Ψώνια σε παζάρι της Τζαϊπούρ", scene: "Είσαι σε πολύχρωμο παζάρι της Τζαϊπούρ και κοιτάζεις τσάντες και ρούχα. Θέλεις να ρωτήσεις τιμή, χρώμα και να παζαρέψεις ευγενικά.", lines: [{ who: "them", hi: "नमस्ते, क्या देखना है?", el: "Γεια σας, τι θέλετε να δείτε;" }, { who: "you", hi: "यह बैग कितने का है?", el: "Πόσο κάνει αυτή η τσάντα;" }, { who: "them", hi: "यह एक हज़ार रुपये का है।", el: "Αυτή κάνει χίλιες ρουπίες." }, { who: "you", hi: "बहुत महंगा है।", el: "Είναι πολύ ακριβή." }, { who: "them", hi: "अच्छा बैग है, हाथ से बना है।", el: "Είναι καλή τσάντα, χειροποίητη." }, { who: "you", hi: "सस्ता दीजिए, कृपया।", el: "Δώστε τη φθηνότερα, παρακαλώ." }, { who: "them", hi: "आठ सौ रुपये ठीक है।", el: "Οκτακόσιες ρουπίες είναι εντάξει." }, { who: "you", hi: "दूसरा रंग है?", el: "Υπάρχει άλλο χρώμα;" }, { who: "them", hi: "हाँ, नीला और काला है।", el: "Ναι, υπάρχει μπλε και μαύρο." }, { who: "you", hi: "मुझे काला रंग पसंद है।", el: "Μου αρέσει το μαύρο χρώμα." }, { who: "them", hi: "ठीक है, काला बैग लीजिए।", el: "Εντάξει, πάρτε τη μαύρη τσάντα." }, { who: "you", hi: "धन्यवाद, यह अच्छा है।", el: "Ευχαριστώ, είναι ωραία." }] },
{ title: "Στο φαρμακείο", scene: "Μπαίνεις σε φαρμακείο στην Πούνε γιατί έχεις πονοκέφαλο και λίγο πυρετό. Θέλεις απλό φάρμακο και οδηγίες.", lines: [{ who: "them", hi: "नमस्ते, क्या समस्या है?", el: "Γεια σας, ποιο είναι το πρόβλημα;" }, { who: "you", hi: "मेरे सिर में दर्द है।", el: "Πονάει το κεφάλι μου." }, { who: "them", hi: "बुखार है?", el: "Έχετε πυρετό;" }, { who: "you", hi: "जी हाँ, थोड़ा बुखार है।", el: "Ναι, έχω λίγο πυρετό." }, { who: "them", hi: "यह दवाई लीजिए।", el: "Πάρτε αυτό το φάρμακο." }, { who: "you", hi: "कैसे लेना है?", el: "Πώς πρέπει να το πάρω;" }, { who: "them", hi: "दिन में दो बार।", el: "Δύο φορές την ημέρα." }, { who: "you", hi: "पानी के साथ?", el: "Με νερό;" }, { who: "them", hi: "जी हाँ, पानी के साथ।", el: "Ναι, με νερό." }, { who: "you", hi: "डॉक्टर चाहिए?", el: "Χρειάζομαι γιατρό;" }, { who: "them", hi: "अगर बुखार ज़्यादा हो, डॉक्टर को दिखाइए।", el: "Αν ο πυρετός είναι υψηλός, δείτε γιατρό." }, { who: "you", hi: "धन्यवाद, मैं समझ गया।", el: "Ευχαριστώ, κατάλαβα." }] },
{ title: "Μικρή κουβέντα με ντόπιο σε τρένο", scene: "Ταξιδεύεις με τρένο από Δελχί προς Άγκρα και κάθεσαι δίπλα σε έναν ντόπιο επιβάτη. Κάνετε φιλική κουβέντα για ταξίδι, χώρα και φαγητό.", lines: [{ who: "you", hi: "नमस्ते, यह सीट खाली है?", el: "Γεια σας, είναι ελεύθερη αυτή η θέση;" }, { who: "them", hi: "जी हाँ, बैठिए।", el: "Ναι, καθίστε." }, { who: "you", hi: "धन्यवाद, मेरा नाम एलेनी है।", el: "Ευχαριστώ, το όνομά μου είναι Ελένη." }, { who: "them", hi: "नमस्ते, मेरा नाम राहुल है।", el: "Γεια σας, το όνομά μου είναι Ραχούλ." }, { who: "you", hi: "आप कहाँ से हैं?", el: "Από πού είστε;" }, { who: "them", hi: "मैं दिल्ली से हूँ। आप?", el: "Είμαι από το Δελχί. Εσείς;" }, { who: "you", hi: "मैं ग्रीस से हूँ।", el: "Είμαι από την Ελλάδα." }, { who: "them", hi: "भारत कैसा लगा?", el: "Πώς σας φάνηκε η Ινδία;" }, { who: "you", hi: "बहुत अच्छा लगा। खाना भी अच्छा है।", el: "Μου άρεσε πολύ. Και το φαγητό είναι καλό." }, { who: "them", hi: "आपको मसालेदार खाना पसंद है?", el: "Σας αρέσει το πικάντικο φαγητό;" }, { who: "you", hi: "थोड़ा पसंद है, लेकिन ज़्यादा नहीं।", el: "Μου αρέσει λίγο, αλλά όχι πολύ." }, { who: "them", hi: "अच्छा, आगरा में आपका स्वागत है।", el: "Ωραία, καλώς ήρθατε στην Άγκρα." }] }
